/**
 * Advanced Example Module Public API
 *
 * Centralized exports for the Advanced Example module.
 * Import from this file when using module functionality
 * from other parts of the application.
 *
 * IMPORTANT: Only import from this index file, never from internal files.
 *
 * @module modules/_examples/advanced-example
 *
 * @example
 * ```typescript
 * import {
 *   AdvancedExampleModule,
 *   AdvancedExampleService,
 *   advancedExampleRoutes,
 *   type AdvancedExample,
 *   type CreateExampleRequest,
 *   ExampleStatus,
 * } from '@/modules/_examples/advanced-example';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { AdvancedExampleModule, default } from '@/modules/_examples/advanced-example/advanced-example.module';
export type {
  AdvancedExampleModuleContext,
  ModuleHooks,
} from '@/modules/_examples/advanced-example/advanced-example.module';

// -----------------------------------------------------------------------------
// Services
// -----------------------------------------------------------------------------

export { AdvancedExampleService } from '@/modules/_examples/advanced-example/advanced-example.service';
export type {
  CreateExampleResponse,
  UpdateExampleResponse,
  StatusChangeResponse,
  ProcessExampleResponse,
  BulkOperationResponse,
  ItemResponse,
} from '@/modules/_examples/advanced-example/advanced-example.service';

// -----------------------------------------------------------------------------
// Repository
// -----------------------------------------------------------------------------

export { AdvancedExampleRepository } from '@/modules/_examples/advanced-example/advanced-example.repository';
export type {
  CreateExampleData,
  UpdateExampleData,
  CreateItemData,
  UpdateItemData,
} from '@/modules/_examples/advanced-example/advanced-example.repository';

// -----------------------------------------------------------------------------
// Controller
// -----------------------------------------------------------------------------

export { AdvancedExampleController } from '@/modules/_examples/advanced-example/advanced-example.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  advancedExampleRoutes,
  itemRoutes,
  buildExampleApiPath,
  buildExampleAdminPath,
  buildItemApiPath,
  isPublicExampleRoute,
  isProtectedExampleRoute,
  exampleEndpoints,
  getAllEndpoints,
  getEndpointsByMethod,
  getProtectedEndpoints,
  getPublicEndpoints,
} from '@/modules/_examples/advanced-example/advanced-example.routes';
export type {
  RouteConfig,
  EndpointMetadata,
} from '@/modules/_examples/advanced-example/advanced-example.routes';

// -----------------------------------------------------------------------------
// Events
// -----------------------------------------------------------------------------

export {
  ADVANCED_EXAMPLE_EVENTS,
  ALL_EXAMPLE_EVENTS,
  emitExampleCreated,
  emitExampleUpdated,
  emitExampleDeleted,
  emitExampleStatusChanged,
  emitExampleProcessed,
  emitItemCreated,
  emitItemUpdated,
  emitItemDeleted,
  emitBulkOperation,
  registerExampleEventListeners,
} from '@/modules/_examples/advanced-example/advanced-example.events';
export type {
  AdvancedExampleEventName,
  AdvancedExampleModuleEvents,
  ExampleCreatedEventPayload,
  ExampleUpdatedEventPayload,
  ExampleDeletedEventPayload,
  ExampleStatusChangedEventPayload,
  ExampleProcessedEventPayload,
  ItemCreatedEventPayload,
  ItemUpdatedEventPayload,
  ItemDeletedEventPayload,
  BulkOperationEventPayload,
  ProcessStartedEventPayload,
  EventHandler,
} from '@/modules/_examples/advanced-example/advanced-example.events';

// -----------------------------------------------------------------------------
// Hooks
// -----------------------------------------------------------------------------

export {
  createHookManager,
  defaultHookManager,
  Hook,
  CRUD_HOOKS,
  executeHookChain,
} from '@/modules/_examples/advanced-example/advanced-example.hooks';
export type {
  HookName,
  HookContextMap,
  HookHandler,
  HookRegistration,
  HookExecutionResult,
  HookManager,
  BeforeCreateContext,
  AfterCreateContext,
  BeforeUpdateContext,
  AfterUpdateContext,
  BeforeDeleteContext,
  AfterDeleteContext,
  ProcessContext,
} from '@/modules/_examples/advanced-example/advanced-example.hooks';

// -----------------------------------------------------------------------------
// Types - Enums
// -----------------------------------------------------------------------------

export {
  ExampleStatus,
  ExampleType,
  ExamplePriority,
} from '@/modules/_examples/advanced-example/advanced-example.types';

// -----------------------------------------------------------------------------
// Types - Core Entities
// -----------------------------------------------------------------------------

export type {
  // Entity types
  AdvancedExample,
  AdvancedExampleWithRelations,
  ExampleItem,
  ExampleSettings,
  AdvancedExampleModuleSettings,

  // Request types
  CreateExampleRequest,
  UpdateExampleRequest,
  ChangeStatusRequest,
  ProcessExampleRequest,
  BulkOperationRequest,
  CreateExampleItemRequest,
  UpdateExampleItemRequest,

  // Query types
  ListExamplesQuery,
  ListExampleItemsQuery,

  // Response types
  PaginatedResult,
  ExampleSummary,
  ExampleStatistics,

  // Event payload types
  BaseEventPayload,
} from '@/modules/_examples/advanced-example/advanced-example.types';

// -----------------------------------------------------------------------------
// Schemas (Zod validation)
// -----------------------------------------------------------------------------

export {
  // Base schemas
  nameSchema,
  slugSchema,
  optionalSlugSchema,
  descriptionSchema,
  cuidSchema,
  optionalCuidSchema,
  sortOrderSchema,
  tagsSchema,

  // Enum schemas
  exampleStatusSchema,
  exampleTypeSchema,
  examplePrioritySchema,

  // Settings schema
  exampleSettingsSchema,

  // Item schemas
  createItemNestedSchema,
  createItemSchema,
  updateItemSchema,

  // Example schemas
  createExampleSchema,
  updateExampleSchema,
  changeStatusSchema,
  processExampleSchema,
  bulkOperationSchema,

  // Query schemas
  listExamplesQuerySchema,
  listItemsQuerySchema,

  // Response schema
  exampleResponseSchema,

  // Utility functions
  generateSlug,
  isValidSlug,
  isValidStatusTransition,
  getAllowedTransitions,
  parseSettings,
} from '@/modules/_examples/advanced-example/advanced-example.schema';

export type {
  ExampleSettingsInput,
  CreateItemInput,
  UpdateItemInput,
  CreateExampleInput,
  UpdateExampleInput,
  ChangeStatusInput,
  ProcessExampleInput,
  BulkOperationInput,
  ListExamplesQueryInput,
  ListItemsQueryInput,
} from '@/modules/_examples/advanced-example/advanced-example.schema';
